// @ts-nocheck
// Round country-flag avatars (ISO 3166-1 alpha-2 lowercase -> data URI PNG).
// Source: user-provided circular flag icons in /png. Used as the customer avatar in Orders HQ.
// Markets: NL, BE, DE, AT, PL, SE, NO, DK, CZ, SK, HU, FR.
export const FLAG_AVATARS: Record<string, string> = {
  nl: "data:image/png;base64,",
  be: "data:image/png;base64,",
  de: "data:image/png;base64,",
  at: "data:image/png;base64,",
  pl: "data:image/png;base64,",
  se: "data:image/png;base64,",
  no: "data:image/png;base64,",
  dk: "data:image/png;base64,",
  cz: "data:image/png;base64,",
  sk: "data:image/png;base64,",
  hu: "data:image/png;base64,",
  fr: "data:image/png;base64,",
}

export function getFlagAvatar(code?: string): string | undefined {
  if (!code) return undefined
  return FLAG_AVATARS[code.toLowerCase()]
}
